import java.sql.*;

public class SQLInjectionFixed {

    public static void main(String[] args) {
        try {
            // Simulating user input
            String userInput = "'; DROP TABLE users; --";

            // Connecting to a SQLite database (for demonstration purposes)
            Connection conn = DriverManager.getConnection("jdbc:sqlite:test.db");

            // Using a prepared statement with parameterized query to prevent SQL injection
            String sql = "SELECT * FROM users WHERE username = ?";
            PreparedStatement pstmt = conn.prepareStatement(sql);

            // Setting the parameter value using setString method
            pstmt.setString(1, userInput);

            // Executing the query
            ResultSet rs = pstmt.executeQuery();

            // Processing the result set (not relevant for demonstrating the vulnerability)

        } catch (SQLException e) {
            e.printStackTrace();
        }
    }
}

